window.ComfinoPaywallInit={init:()=>{const b=document.getElementById("comfino-iframe-container");document.getElementById("comfino-iframe-container")?.querySelector("#comfino-paywall-container")?.remove();if(null==b)ComfinoPaywallFrontend.logEvent("Comfino paywall iframe container not found.","warning");else if(null!==b.querySelector("#comfino-paywall-container")&&ComfinoPaywallFrontend.isFrontendInitSet())ComfinoPaywallFrontend.logEvent("Comfino paywall iframe already initialized.","info",b);else{var c=
ComfinoPaywallFrontend.createPaywallIframe(ComfinoPaywallData.paywallUrl,ComfinoPaywallData.paywallOptions),e=document.getElementById("pay-with-comfino")??document.querySelector('input[data-module-name^="comfino"]');if("priceModifier"in e.dataset){let a=parseInt(e.dataset.priceModifier);Number.isNaN(a)||(c.src+=(c.src.includes("?")?"&":"?")+"priceModifier="+a)}ComfinoPaywallData.paywallOptions.onUpdateOrderPaymentState=a=>{ComfinoPaywallFrontend.logEvent("updateOrderPaymentState PrestaShop","debug",
a);const h=new URL(ComfinoPaywallData.paywallStateUrl),f=new FormData;a={loan_amount:a.loanAmount,loan_type:a.loanType,loan_term:a.loanTerm,price_modifier:a.priceModifier};for(let d in a)f.append(d,a[d]);const g=h.toString();fetch(g,{method:"POST",body:f}).then(d=>{ComfinoPaywallFrontend.logEvent("updateOrderPaymentState PrestaShop","debug",g,d)})};b.appendChild(c);ComfinoPaywallFrontend.init(e,c,ComfinoPaywallData.paywallOptions)}},initWithObserver:()=>{ComfinoPaywallInit.init();if(!ComfinoPaywallFrontend.isFrontendInitSet()){var b=
document.getElementById("pay-with-comfino")??document.querySelector('input[data-module-name^="comfino"]');if(b){ComfinoPaywallFrontend.logEvent("Paywall initialization with 'display' prop observer.","debug");const c=new MutationObserver(()=>{"block"===getComputedStyle(b).display&&(ComfinoPaywallInit.init(),ComfinoPaywallFrontend.isFrontendInitSet()&&c.disconnect())});c.observe(b,{attributes:!0,attributeFilter:["style"]})}}}};
"complete"===document.readyState?ComfinoPaywallInit.initWithObserver():document.addEventListener("readystatechange",()=>{"complete"===document.readyState&&ComfinoPaywallInit.initWithObserver()});
